sql:
SELECT project_name
FROM projects
WHERE project_id = 1;

SELECT COUNT(*) AS completed_tasks_count
FROM tasks
WHERE status = 'Completed';

SELECT task_id, description, due_date, status
FROM tasks
WHERE assigned_to = 1 AND status = 'Completed';

external_knowledge:
- In this metaphor, "seeds" represent tasks;
- "Jane Doe" is the specific user whose tasks we are counting;
- The "garden of responsibilities" is a metaphorical reference to the tasks that are assigned to individuals in the context of the task management system.

sql:
SELECT COUNT(task_id) AS task_count
FROM tasks
WHERE assigned_to = (SELECT user_id FROM users WHERE user_name = 'Jane Doe');

SELECT T1.description, T2.department_name
FROM tasks AS T1
JOIN departments AS T2 ON T1.department_id = T2.department_id;

SELECT task_id, description, due_date
FROM tasks
WHERE status = 'Completed';

SELECT t.description, u.user_name
FROM tasks t
JOIN users u ON t.assigned_to = u.user_id;
